import sqlite3
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]


def open_database():
    connection = sqlite3.connect(":memory:")
    connection.row_factory = sqlite3.Row
    connection.executescript((ROOT / "db/schema.sql").read_text(encoding="utf-8"))
    return connection


def test_single_tenant_order_summary():
    connection = open_database()
    connection.execute(
        "INSERT INTO customers (tenant_id, id, name) VALUES (?, ?, ?)",
        ("tenant-a", 7, "Ada"),
    )
    connection.execute(
        "INSERT INTO orders (tenant_id, id, customer_id, total_cents) VALUES (?, ?, ?, ?)",
        ("tenant-a", 11, 7, 4200),
    )
    rows = connection.execute(
        (ROOT / "db/order_summary.sql").read_text(encoding="utf-8"),
        {"tenant_id": "tenant-a"},
    ).fetchall()
    assert [dict(row) for row in rows] == [
        {"order_id": 11, "customer_name": "Ada", "total_cents": 4200}
    ]


def test_tenant_totals_are_filtered():
    connection = open_database()
    connection.execute(
        "INSERT INTO customers (tenant_id, id, name) VALUES (?, ?, ?)",
        ("tenant-a", 99, "Totals Customer"),
    )
    connection.execute(
        "INSERT INTO orders (tenant_id, id, customer_id, total_cents) VALUES (?, ?, ?, ?)",
        ("tenant-a", 1, 99, 1200),
    )
    row = connection.execute(
        (ROOT / "db/order_totals.sql").read_text(encoding="utf-8"),
        {"tenant_id": "tenant-a"},
    ).fetchone()
    assert dict(row) == {"order_count": 1, "total_cents": 1200}
